@page "/notifications"
@using NotificationsApp.Services
@rendermode InteractiveServer
@implements IDisposable
@inject NotificationService NotificationService

<PageTitle>Notifications</PageTitle>

<h1>Notifications <span class="badge bg-primary">@_notifications.Count</span></h1>

@if (_notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var notification in _notifications.OrderByDescending(n => n.Timestamp))
        {
            <li class="list-group-item">
                <strong>@notification.Message</strong>
                <br />
                <small class="text-muted">@notification.Timestamp.ToString("g")</small>
            </li>
        }
    </ul>
}

@code {
    private List<Notification> _notifications = new();
    private CancellationTokenSource? _cts;

    // Load initial data during SSR — this renders into the first HTML response.
    protected override void OnInitialized()
    {
        _notifications = NotificationService.GetNotifications();
    }

    // OnAfterRenderAsync with firstRender == true fires only on the interactive
    // runtime (not during static SSR), so the polling loop starts only when the
    // component is live in the browser.
    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken cancellationToken)
    {
        while (!cancellationToken.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), cancellationToken)
                      .ConfigureAwait(false);

            if (cancellationToken.IsCancellationRequested)
                break;

            var lastId = _notifications.Count > 0
                ? _notifications.Max(n => n.Id)
                : 0;

            var newOnes = NotificationService.GetNotificationsSince(lastId);

            if (newOnes.Count > 0)
            {
                _notifications.AddRange(newOnes);
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

